ruleSearch.bookList:
.search-list<js>
importClass(org.jsoup.Jsoup);
var bookCount=2,searchList=[];
function aa(b){
return doc.select("[property="+b+"]").attr("content")
}

for(var i=0;i<bookCount;i++){
var url=result.select("li:eq("+i+") .tit").attr("href");
var doc=Jsoup.parse(java.ajax(url));
searchList.push({
name:aa("og:novel:book_name"),
author:aa("og:novel:author"),
tag:aa("og:novel:category")+','+String(aa("og:novel:status")).replace(/中|已/,''),
cover:aa("og:image"),
intro:String(aa("og:description")).replace(/简介.\s*/,''),
last:aa("og:novel:latest_chapter_name"),
url:String(url).replace(/book/,'home/chapter/lists/id')
})
}
searchList
</js>
